class Solution {
public:
    string solveEquation(string equation) {
        int coeff = 0, constant = 0;
        int sign = 1;
        int n = equation.size();
        int i = 0;
        while (i < n) {
            if (equation[i] == '=') {
                sign = 1;
                i++;
                continue;
            }
            int num = 0;
            bool isCoeff = false;
            if (equation[i] == '-') {
                sign = -sign;
                i++;
            } else if (equation[i] == '+') {
                i++;
            }
            while (i < n && isdigit(equation[i])) {
                num = num * 10 + (equation[i] - '0');
                i++;
                isCoeff = true;
            }
            if (i < n && equation[i] == 'x') {
                if (!isCoeff) num = 1;
                coeff += sign * num;
                i++;
            } else {
                constant -= sign * num;
            }
        }
        if (coeff == 0) {
            if (constant == 0) return "Infinite solutions";
            else return "No solution";
        }
        int x = constant / coeff;
        return "x=" + to_string(x);
    }
};
